# 203 Central Logger Package Installer - NeoLegal Production Platform

from pathlib import Path

BASE = Path(r"C:\Users\MSI\Desktop\kik_proje")
PY = BASE / ".py"
PKG = PY / "203"

def write(name, text):
    p = PKG / name
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(text, encoding="utf-8")

CONFIG = '# -*- coding: utf-8 -*-\nfrom pathlib import Path\n\nBASE_DIR = Path(r"C:\\Users\\MSI\\Desktop\\kik_proje")\nPY_DIR = BASE_DIR / ".py"\nSTATE_DIR = BASE_DIR / "production_state"\nREPORT_DIR = BASE_DIR / "raporlar"\nLOG_DIR = STATE_DIR / "logs"\n\nPLATFORM_LOG_FILE = LOG_DIR / "203_platform.log.jsonl"\nLOGGER_STATE_DIR = STATE_DIR / "logger"\n\nEVENT_LOG_FILE = STATE_DIR / "event_bus" / "201_event_bus.jsonl"\n\nVALID_LEVELS = ["DEBUG", "INFO", "WARNING", "ERROR", "CRITICAL"]\n'

UTILS = '# -*- coding: utf-8 -*-\nimport json\nimport shutil\nfrom pathlib import Path\nfrom datetime import datetime\n\ndef now_stamp():\n    return datetime.now().strftime("%Y%m%d_%H%M%S")\n\ndef now_text():\n    return datetime.now().strftime("%Y-%m-%d %H:%M:%S")\n\ndef ensure_dirs(*dirs):\n    for d in dirs:\n        Path(d).mkdir(parents=True, exist_ok=True)\n\ndef disk_free_gb(path):\n    usage = shutil.disk_usage(str(path))\n    return round(usage.free / (1024 ** 3), 2)\n\ndef safe_read(path, limit_chars=1000000):\n    path = Path(path)\n    if not path.exists():\n        return ""\n    for enc in ("utf-8", "utf-8-sig", "cp1254", "latin-1"):\n        try:\n            return path.read_text(encoding=enc, errors="ignore")[:limit_chars]\n        except Exception:\n            pass\n    return ""\n\ndef write_json(path, data):\n    path = Path(path)\n    path.parent.mkdir(parents=True, exist_ok=True)\n    path.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")\n'

LOGGER = '# -*- coding: utf-8 -*-\nimport json\nimport uuid\nfrom config import BASE_DIR, STATE_DIR, REPORT_DIR, LOG_DIR, PLATFORM_LOG_FILE, VALID_LEVELS\nfrom utils import now_text, now_stamp, ensure_dirs, disk_free_gb, write_json\n\ndef make_log(level="INFO", source="203 Logger", message="", payload=None, correlation_id=None):\n    level = str(level).upper()\n    if level not in VALID_LEVELS:\n        level = "INFO"\n\n    return {\n        "log_id": str(uuid.uuid4()),\n        "correlation_id": correlation_id or str(uuid.uuid4()),\n        "level": level,\n        "source": source,\n        "message": message,\n        "created_at": now_text(),\n        "payload": payload or {},\n    }\n\ndef write_log(record):\n    ensure_dirs(STATE_DIR, REPORT_DIR, LOG_DIR)\n    with PLATFORM_LOG_FILE.open("a", encoding="utf-8") as f:\n        f.write(json.dumps(record, ensure_ascii=False) + "\\n")\n    return record\n\ndef test_log():\n    record = make_log(\n        level="INFO",\n        source="203 Central Logger",\n        message="Central logger test log",\n        payload={"platform": "NeoLegal Production Platform", "test": True},\n    )\n    return write_log(record)\n\ndef run_test():\n    ensure_dirs(STATE_DIR, REPORT_DIR, LOG_DIR)\n    ts = now_stamp()\n    record = test_log()\n    result = {"score": 100, "decision": "LOGGER READY", "errors": [], "warnings": []}\n    state = STATE_DIR / f"203_logger_test_state_{ts}.json"\n    report = REPORT_DIR / f"203_logger_test_raporu_{ts}.txt"\n    payload = {\n        "module": "203 Central Logger Test",\n        "created_at": now_text(),\n        "log_file": str(PLATFORM_LOG_FILE),\n        "disk_free_gb": disk_free_gb(BASE_DIR),\n        "record": record,\n        "result": result,\n    }\n    write_json(state, payload)\n    report.write_text("\\n".join([\n        "="*80,\n        "203 CENTRAL LOGGER TEST",\n        "="*80,\n        f"Score    : {result[\'score\']} / 100",\n        f"Decision : {result[\'decision\']}",\n        f"Log File : {PLATFORM_LOG_FILE}",\n        "",\n        "LOG RECORD",\n        "-"*80,\n        json.dumps(record, ensure_ascii=False, indent=2),\n        "",\n        "Dosyalar:",\n        str(PLATFORM_LOG_FILE),\n        str(state),\n        str(report),\n    ]), encoding="utf-8")\n    return {"record": record, "result": result, "paths": {"log": str(PLATFORM_LOG_FILE), "state": str(state), "report": str(report)}}\n'

AUDITOR = '# -*- coding: utf-8 -*-\nimport json\nfrom config import BASE_DIR, STATE_DIR, REPORT_DIR, LOG_DIR, PLATFORM_LOG_FILE, VALID_LEVELS\nfrom utils import now_text, now_stamp, ensure_dirs, disk_free_gb, write_json\n\ndef read_logs(limit=None):\n    ensure_dirs(STATE_DIR, REPORT_DIR, LOG_DIR)\n    if not PLATFORM_LOG_FILE.exists():\n        return [], []\n    lines = PLATFORM_LOG_FILE.read_text(encoding="utf-8", errors="ignore").splitlines()\n    if limit:\n        lines = lines[-limit:]\n    records = []\n    invalid = []\n    for i, line in enumerate(lines, start=1):\n        if not line.strip():\n            continue\n        try:\n            rec = json.loads(line)\n            rec["_line_no"] = i\n            records.append(rec)\n        except Exception:\n            invalid.append({"line_no": i, "raw": line[:500]})\n    return records, invalid\n\ndef summarize(records, invalid):\n    by_level = {}\n    by_source = {}\n    missing_required = []\n    required = ["log_id", "correlation_id", "level", "source", "message", "created_at", "payload"]\n    for r in records:\n        for field in required:\n            if field not in r:\n                missing_required.append({"line_no": r.get("_line_no"), "missing": field})\n        level = r.get("level", "UNKNOWN")\n        source = r.get("source", "UNKNOWN")\n        by_level[level] = by_level.get(level, 0) + 1\n        by_source[source] = by_source.get(source, 0) + 1\n    problem_logs = [r for r in records if str(r.get("level", "")).upper() in ("WARNING", "ERROR", "CRITICAL")]\n    return {\n        "total": len(records),\n        "invalid": len(invalid),\n        "missing_required": len(missing_required),\n        "by_level": by_level,\n        "by_source": by_source,\n        "problem_logs": problem_logs,\n        "missing_required_samples": missing_required[:20],\n    }\n\ndef evaluate(summary):\n    score = 100\n    errors = []\n    warnings = []\n    if summary["total"] == 0:\n        score -= 20\n        warnings.append("Log dosyası boş.")\n    if summary["invalid"] > 0:\n        score -= min(30, summary["invalid"] * 5)\n        errors.append(f"Bozuk log satırı var: {summary[\'invalid\']}")\n    if summary["missing_required"] > 0:\n        score -= min(20, summary["missing_required"] * 3)\n        warnings.append(f"Zorunlu alan eksik log var: {summary[\'missing_required\']}")\n    err_count = summary["by_level"].get("ERROR", 0) + summary["by_level"].get("CRITICAL", 0)\n    warn_count = summary["by_level"].get("WARNING", 0)\n    if err_count:\n        score -= min(25, err_count * 5)\n        errors.append(f"ERROR/CRITICAL log var: {err_count}")\n    if warn_count:\n        score -= min(10, warn_count * 2)\n        warnings.append(f"WARNING log var: {warn_count}")\n    score = max(0, min(100, score))\n    decision = "LOGGER AUDIT REVIEW" if errors else ("LOGGER AUDIT CLEAN" if score >= 95 else "LOGGER AUDIT LOW REVIEW")\n    return {"score": score, "decision": decision, "errors": errors, "warnings": warnings}\n\ndef run(limit=50, problems=False):\n    ensure_dirs(STATE_DIR, REPORT_DIR, LOG_DIR)\n    ts = now_stamp()\n    records, invalid = read_logs(limit=None)\n    summary = summarize(records, invalid)\n    result = evaluate(summary)\n\n    if problems:\n        display = summary["problem_logs"][-limit:]\n    else:\n        display = records[-limit:]\n\n    state = STATE_DIR / f"203_logger_audit_state_{ts}.json"\n    report = REPORT_DIR / f"203_logger_audit_raporu_{ts}.txt"\n    payload = {\n        "module": "203 Central Logger Auditor",\n        "created_at": now_text(),\n        "log_file": str(PLATFORM_LOG_FILE),\n        "disk_free_gb": disk_free_gb(BASE_DIR),\n        "summary": {k:v for k,v in summary.items() if k != "problem_logs"},\n        "display_logs": display,\n        "result": result,\n    }\n    write_json(state, payload)\n\n    lines = [\n        "="*80,\n        "203 CENTRAL LOGGER AUDITOR",\n        "="*80,\n        f"Score          : {result[\'score\']} / 100",\n        f"Decision       : {result[\'decision\']}",\n        f"Total Logs     : {summary[\'total\']}",\n        f"Invalid Lines  : {summary[\'invalid\']}",\n        f"Problem Logs   : {len(summary[\'problem_logs\'])}",\n        f"By Level       : {summary[\'by_level\']}",\n        f"By Source      : {summary[\'by_source\']}",\n        "",\n        "DISPLAY LOGS",\n        "-"*80,\n    ]\n    for r in display:\n        lines.append(f"{r.get(\'created_at\')} | {r.get(\'level\')} | {r.get(\'source\')} | {r.get(\'message\')}")\n    lines += [\n        "",\n        "ERRORS",\n        "-"*80,\n    ]\n    if result["errors"]:\n        for e in result["errors"]:\n            lines.append(f"- {e}")\n    else:\n        lines.append("Errors: 0")\n    lines += [\n        "",\n        "WARNINGS",\n        "-"*80,\n    ]\n    if result["warnings"]:\n        for w in result["warnings"]:\n            lines.append(f"- {w}")\n    else:\n        lines.append("Warnings: 0")\n    lines += [\n        "",\n        "Dosyalar:",\n        str(PLATFORM_LOG_FILE),\n        str(state),\n        str(report),\n    ]\n    report.write_text("\\n".join(lines), encoding="utf-8")\n    return {"summary": summary, "result": result, "paths": {"log": str(PLATFORM_LOG_FILE), "state": str(state), "report": str(report)}}\n'

MANAGER = '# -*- coding: utf-8 -*-\nimport argparse\nfrom logger import run_test\nfrom auditor import run as run_audit\n\ndef main():\n    parser = argparse.ArgumentParser()\n    parser.add_argument("--status", action="store_true")\n    parser.add_argument("--test-log", action="store_true")\n    parser.add_argument("--audit", action="store_true")\n    parser.add_argument("--tail", type=int, default=50)\n    parser.add_argument("--problems", action="store_true")\n    args = parser.parse_args()\n\n    if args.test_log:\n        res = run_test()\n        print("="*80)\n        print("203 CENTRAL LOGGER TEST TAMAMLANDI")\n        print("="*80)\n        print(f"Decision : {res[\'result\'][\'decision\']} ({res[\'result\'][\'score\']}/100)")\n        print("")\n        print("Dosyalar:")\n        print(res["paths"]["log"])\n        print(res["paths"]["report"])\n        return\n\n    res = run_audit(limit=args.tail, problems=args.problems)\n    print("="*80)\n    print("203 CENTRAL LOGGER AUDIT TAMAMLANDI")\n    print("="*80)\n    print(f"Decision     : {res[\'result\'][\'decision\']} ({res[\'result\'][\'score\']}/100)")\n    print(f"Total Logs   : {res[\'summary\'][\'total\']}")\n    print(f"Problem Logs : {len(res[\'summary\'][\'problem_logs\'])}")\n    print(f"Invalid      : {res[\'summary\'][\'invalid\']}")\n    print("")\n    print("Dosyalar:")\n    print(res["paths"]["log"])\n    print(res["paths"]["report"])\n\nif __name__ == "__main__":\n    main()\n'

BRIDGE = '# -*- coding: utf-8 -*-\nimport sys\nfrom pathlib import Path\nPACKAGE_DIR = Path(__file__).resolve().parent / "203"\nsys.path.insert(0, str(PACKAGE_DIR))\nfrom manager import main\nif __name__ == "__main__":\n    main()\n'

README = '# 203 Central Logger Package\n\nNeoLegal Production Platform için merkezi loglama paketidir.\n\nKomutlar:\npython ".py\\203_Central_Logger.py" --status\npython ".py\\203_Central_Logger.py" --test-log\npython ".py\\203_Central_Logger.py" --audit --tail=20\npython ".py\\203_Central_Logger.py" --problems\n'

